# test_intersection.py
import pytest

from your_module import intersection  # replace with the actual module name


@pytest.mark.parametrize(
    "lst1,lst2,expected",
    [
        ([1, 2, 3], [2, 3, 4], [2, 3]),
        ([1, 2, 2, 3, 3, 4], [2, 3], [2, 3]),
        ([3, 2, 1], [1, 2, 3], [3, 2, 1]),
        (["a", "b", "c"], ["b", "c", "d"], ["b", "c"]),
        ([1, "1", None], [None, "1", 2], ["1", None]),
    ],
)
def test_intersection_happy_path(lst1, lst2, expected):
    assert intersection(lst1, lst2) == expected


def test_intersection_preserves_order_from_first_list():
    assert intersection([4, 1, 3, 2], [1, 2, 3, 4]) == [4, 1, 3, 2]


def test_intersection_removes_duplicates_from_result():
    assert intersection([1, 1, 2, 2, 3, 3], [1, 2, 3]) == [1, 2, 3]


def test_intersection_empty_first_list():
    assert intersection([], [1, 2, 3]) == []


def test_intersection_empty_second_list():
    assert intersection([1, 2, 3], []) == []


def test_intersection_both_lists_empty():
    assert intersection([], []) == []


def test_intersection_no_common_items():
    assert intersection([1, 2, 3], [4, 5, 6]) == []


def test_intersection_all_items_common_with_duplicates():
    assert intersection([1, 1, 1], [1, 1]) == [1]


def test_intersection_does_not_modify_inputs():
    lst1 = [1, 2, 2, 3]
    lst2 = [2, 3, 4]
    original_lst1 = lst1.copy()
    original_lst2 = lst2.copy()

    intersection(lst1, lst2)

    assert lst1 == original_lst1
    assert lst2 == original_lst2


def test_intersection_with_tuple_inputs_works_despite_type_hint():
    assert intersection((1, 2, 3), (2, 3, 4)) == [2, 3]


def test_intersection_with_string_inputs_works_as_iterables():
    assert intersection("banana", "an") == ["a", "n"]


def test_intersection_raises_type_error_when_second_list_contains_unhashable_item():
    with pytest.raises(TypeError):
        intersection([1, 2, 3], [[1], 2, 3])


def test_intersection_raises_type_error_when_first_list_contains_unhashable_item():
    with pytest.raises(TypeError):
        intersection([[1], 2, 3], [1, 2, 3])


def test_intersection_raises_type_error_when_first_argument_is_not_iterable():
    with pytest.raises(TypeError):
        intersection(None, [1, 2, 3])


def test_intersection_raises_type_error_when_second_argument_is_not_iterable():
    with pytest.raises(TypeError):
        intersection([1, 2, 3], None)
